    "line_077": "<div class=\"lb-preview-help-text\"><strong>Core classes only:</strong> <span class=\"lb-preview-code\">lb-table-frame</span> for border/radius, <span class=\"lb-preview-code\">lb-table-dropdowns-visible</span> for visible overflow, <span class=\"lb-preview-code\">lb-dropdown-layer</span> for multiselect, and <span class=\"lb-preview-code\">lb-select-layer</span> for select.</div>",
