    "line_084": "<button class=\"lb-btn lb-btn-danger\" type=\"button\"><i class=\"pi pi-trash\"></i> Delete</button>",
    "line_085": "<a class=\"lb-btn lb-btn-icon\" href=\"#buttons\"><i class=\"pi pi-cog\"></i> Link button</a>",
    "line_086": "<button class=\"lb-btn lb-btn-primary\" type=\"button\">Action 1</button>",
    "line_087": "<button class=\"lb-btn\" type=\"button\">Action 2</button>",
    "line_088": "<p>A <span class=\"lb-preview-code\">lb-card</span> highlights content with border, radius, and optional shadow.</p>",
    "line_089": "<summary>Section A</summary>",
    "line_090": "<div class=\"lb-collapsible-content\">Content of the open section.</div>",
    "line_091": "<summary>Section B</summary>",
    "line_092": "<div class=\"lb-collapsible-content\">Additional content.</div>",
    "line_093": "<div class=\"note\" style=\"margin-top: var(--lb-space-md, 16px);\">Note box using the existing <span class=\"lb-preview-code\">.note</span>-rule.</div>",
    "line_094": "<div class=\"lb-section-title\">Tables</div>",
    "line_095": "<div class=\"lb-preview-help-text\">This preview shows tables as close to Core as possible: outer borders via <span class=\"lb-preview-code\">.lb-table</span> or <span class=\"lb-preview-code\">.lb-table-frame</span>, dropdown/tooltip overflow via <span class=\"lb-preview-code\">.lb-table-dropdowns-visible</span>, <span class=\"lb-preview-code\">.lb-dropdown-layer</span> and <span class=\"lb-preview-code\">.lb-tooltip-anchor</span>.</div>",
    "line_096": "<h4>Standard table</h4>",
    "line_097": "<p class=\"lb-preview-muted\">The outer border is stabilized via <span class=\"lb-preview-code\">table.lb-table</span> and stays scoped to the DS table component.</p>",
    "line_098": "<p class=\"lb-preview-muted\">Checks the outer border, radius, and separated cell lines of the Core component <span class=\"lb-preview-code\">.lb-table</span>.</p>",
    "line_099": "<th class=\"lb-table-header-cell lb-table-actions\">Action</th>",
    "line_100": "<tr class=\"lb-table-body-row\"><td class=\"lb-table-cell\">Living room</td><td class=\"lb-table-cell\">Online</td><td class=\"lb-table-cell lb-table-actions\"><button class=\"lb-btn lb-btn-sm\">Test</button></td></tr>",
    "line_101": "<tr class=\"lb-table-body-row\"><td class=\"lb-table-cell\">Kitchen</td><td class=\"lb-table-cell\">Offline</td><td class=\"lb-table-cell lb-table-actions\"><button class=\"lb-btn lb-btn-sm\">Test</button></td></tr>",
    "line_102": "<tr class=\"lb-table-footer-row\"><td class=\"lb-table-footer-cell lb-table-actions\" colspan=\"3\"><a href=\"#tables\" class=\"lb-btn lb-btn-sm lb-btn-icon\"><i class=\"pi pi-plus\"></i> Add</a></td></tr>",
    "line_103": "<h4>Compact table</h4>",
    "line_104": "<thead><tr><th>Token</th><th>Effect</th></tr></thead>",
    "line_105": "<tr><td>--lb-primary</td><td><span class=\"lb-preview-swatch\" style=\"background:var(--lb-primary)\"></span>Primary color</td></tr>",
    "line_106": "<tr><td>--lb-card-bg</td><td><span class=\"lb-preview-swatch\" style=\"background:var(--lb-card-bg)\"></span>Card background</td></tr>",
    "line_107": "<tr><td>--lb-table-header-bg</td><td><span class=\"lb-preview-swatch\" style=\"background:var(--lb-table-header-bg)\"></span>Table header</td></tr>",
    "line_108": "<tr><td>--lb-table-footer-bg</td><td><span class=\"lb-preview-swatch\" style=\"background:var(--lb-table-footer-bg)\"></span>Table footer</td></tr>",
    "line_109": "<h4 style=\"margin-top: var(--lb-space-lg, 20px);\">Status cells / Log manager</h4>",
    "line_110": "<p class=\"lb-preview-muted\">Colored status cells must not be overwritten by <span class=\"lb-preview-code\">.lb-table</span>. Inline/legacy alignment remains effective.</p>",
    "line_111": "<td>Info cell stays colored and centered.</td>",
    "line_112": "<td>OK cell stays colored and centered.</td>",
    "line_113": "<td>Warning cell stays colored and centered.</td>",
    "line_114": "<td>Error cell stays colored and centered.</td>",
    "line_115": "<td>Critical cell stays colored and centered.</td>",
    "line_116": "<h4>Table border tokens</h4>",
    "line_117": "<p class=\"lb-preview-muted\">The outer border is part of Core for <span class=\"lb-preview-code\">.lb-table</span>. This demo explicitly shows the border/radius tokens; the other tables also use the real Core table rules.</p>",
    "line_118": "<thead><tr><th>Token</th><th>Effect</th></tr></thead>",
    "line_119": "<tr><td>--lb-table-border-width</td><td>Outer table border width</td></tr>",
    "line_120": "<tr><td>--lb-table-border-style</td><td>Outer table border style</td></tr>",
    "line_121": "<tr><td>--lb-table-border-color</td><td><span class=\"lb-preview-swatch\" style=\"background:var(--lb-table-border-color)\"></span>Outer table border color</td></tr>",
    "line_122": "<tr><td>--lb-table-radius</td><td>Corner radius of the table box</td></tr>",
