    "line_135": "<label class=\"lb-form-label\" for=\"hover_select\">Select hover:</label>",
    "line_136": "<select class=\"lb-select\" id=\"hover_select\" data-role=\"none\"><option>Standard</option><option selected>Hover test</option></select>",
    "line_137": "<h4>Tooltip / mouseover</h4>",
    "line_138": "<p class=\"lb-preview-muted\">Hover or keyboard focus shows a theme-colored tooltip.</p>",
    "line_139": "<button class=\"lb-btn lb-btn-primary\" type=\"button\"><i class=\"pi pi-info-circle\"></i> Traffic lights</button>",
