    "line_141": "GREEN: Everything OK<br>",
    "line_142": "YELLOW: Warning<br>",
    "line_143": "RED: Error",
    "line_144": "<tr><td>--lb-hover-bg</td><td>Generic hover background</td></tr>",
    "line_145": "<tr><td>--lb-hover-text</td><td>generic hover text color</td></tr>",
    "line_146": "<tr><td>--lb-on-light-text</td><td>contrast text for light/white hover backgrounds</td></tr>",
    "line_147": "<tr><td>--lb-btn-hover-text</td><td>button hover text</td></tr>",
    "line_148": "<tr><td>--lb-input-hover-border</td><td>input/select hover border</td></tr>",
    "line_149": "<tr><td>--lb-focus-ring</td><td>focus ring</td></tr>",
    "line_150": "<tr><td>--lb-tooltip-bg</td><td>Tooltip background</td></tr>",
    "line_151": "<tr><td>--lb-tooltip-text</td><td>tooltip text color</td></tr>",
