    "line_156": "<button class=\"lb-btn lb-btn-primary\" type=\"button\" onclick=\"document.getElementById('preview_modal').showModal()\">Open modal</button>",
    "line_157": "<div class=\"lb-section-title\">Example App Store</div>",
    "line_158": "<div class=\"lb-preview-muted\" style=\"margin-bottom:12px;\">AppStore cards as an example of a real LoxBerry system page. The demo uses preview-specific AppStore classes, but only Core/theme tokens for colors, borders, radius and buttons.</div>",
    "line_159": "<p class=\"lb-preview-app-author\">by Dieter Schmidberger</p>",
    "line_160": "<p class=\"lb-preview-app-desc\">The <strong>Roborock</strong> plugin integrates Roborock vacuum robots into Loxone.</p>",
    "line_161": "<div class=\"lb-preview-app-meta\"><span class=\"lb-preview-app-tag\">v1.0.5</span><span class=\"lb-preview-app-tag\">DE, EN</span><span class=\"lb-preview-app-tag\">upd. 2026-06-28</span></div>",
    "line_162": "<div class=\"lb-preview-app-actions\"><a class=\"lb-btn lb-btn-primary lb-btn-sm\" href=\"#appstore\">Install</a><a class=\"lb-btn lb-btn-sm\" href=\"#appstore\">Wiki</a><a class=\"lb-btn lb-btn-sm\" href=\"#appstore\">Forum</a></div>",
    "line_163": "<p class=\"lb-preview-app-author\">by Siggi Ey</p>",
    "line_164": "<p class=\"lb-preview-app-desc\">LoxBerry plugin for local control of TP-Link/Kasa smart plugs including XML export.</p>",
