    "line_166": "<div class=\"lb-preview-app-actions\"><a class=\"lb-btn lb-btn-primary lb-btn-sm\" href=\"#appstore\">Install</a><a class=\"lb-btn lb-btn-sm\" href=\"#appstore\">Wiki</a></div>",
