    "line_168": "<p class=\"lb-preview-app-desc\">Lox-Tools bundles web tools for Loxone, such as command recognition, Modbus helper and log viewer.</p>",
    "line_169": "<div class=\"lb-preview-app-meta\"><span class=\"lb-preview-app-tag\">v1.0.0</span><span class=\"lb-preview-app-tag\">DE/EN</span><span class=\"lb-preview-app-tag\">upd. 2026-06-25</span></div>",
    "line_170": "<div class=\"lb-preview-app-actions\"><button class=\"lb-btn lb-btn-sm\" type=\"button\" disabled>Manual only</button><a class=\"lb-btn lb-btn-sm\" href=\"#appstore\">Wiki</a></div>",
