    "line_178": "<div class=\"lb-preview-app-actions\"><button class=\"lb-btn lb-btn-sm\" type=\"button\" disabled>Manual only</button><a class=\"lb-btn lb-btn-sm\" href=\"#appstore\">Wiki</a></div>",
